For the Factory pattern, imagine an abstract trait and multiple implementations. The factory creates instances without exposing constructors:

```rust
trait Shape {
    fn draw(&self);
}
struct Circle;
impl Shape for Circle { fn draw(&self) {} }
struct Square;
impl Shape for Square { fn draw(&self) {} }

struct ShapeFactory;
implement ShapeFactory {
    pub fn create(shape_type: &str) -> Option<Box<dyn Shape>> {
        match shape_type {
            "circle" => Some(Box::new(Circle)),
            "square" => Some(Box::new(Square)),
            _ => None,
        }
    }
}

let circle = ShapeFactory::create("circle");
```
